const headers = $input.item.json.headers || {};
const body    = $input.item.json.body    || {};
const auth    = headers['authorization'] || headers['Authorization'] || '';
const token   = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };

const action = String(body.action || '').toLowerCase().trim();
const allowed = ['create', 'cancel', 'update'];
if (allowed.indexOf(action) === -1) {
  return { json: { ok: false, status: 400, error: 'Unknown action: ' + (body.action || '(missing)') } };
}

function safeInt(v, def) { const n = parseInt(v, 10); return isNaN(n) ? def : n; }

return { json: {
  token: token,
  action: action,
  auction_id:                 body.auction_id || null,
  item_title:                 (body.item_title || '').toString().slice(0, 200) || null,
  item_description:           (body.item_description || '').toString().slice(0, 2000) || null,
  item_category:              (body.item_category || '').toString().slice(0, 80) || null,
  reserve_price_cents:        safeInt(body.reserve_price_cents, 0),
  min_increment_cents:        safeInt(body.min_increment_cents, 100),
  scheduled_open_at:          body.scheduled_open_at || null,
  scheduled_close_at:         body.scheduled_close_at || null,
  anti_snipe_window_seconds:  safeInt(body.anti_snipe_window_seconds, 30),
  anti_snipe_extend_seconds:  safeInt(body.anti_snipe_extend_seconds, 30),
  anti_snipe_max_extensions:  safeInt(body.anti_snipe_max_extensions, 10)
} };

const rows = $input.item.json;
const row  = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
if (row.user_role !== 'admin') return { json: { ok: false, status: 403, error: 'Admin access required' } };
const x = $('Extract Inputs').item.json;
return { json: Object.assign({ ok: true }, x) };

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const avs = allOf('Lookup LUXI Avatar');
if (avs.length === 0) return { json: { ok: false, status: 404, error: 'LUXI avatar not found — apply db/migrations/avatars-platform-schema.sql first' } };

const x = $('Check Admin').item.json;
if (!x.item_title)         return { json: { ok: false, status: 400, error: 'item_title required' } };
if (!x.scheduled_open_at)  return { json: { ok: false, status: 400, error: 'scheduled_open_at required (ISO 8601)' } };
if (!x.scheduled_close_at) return { json: { ok: false, status: 400, error: 'scheduled_close_at required (ISO 8601)' } };
const openMs  = new Date(x.scheduled_open_at).getTime();
const closeMs = new Date(x.scheduled_close_at).getTime();
if (isNaN(openMs) || isNaN(closeMs))   return { json: { ok: false, status: 400, error: 'scheduled_open_at / scheduled_close_at must be valid ISO 8601 timestamps' } };
if (closeMs <= openMs)                 return { json: { ok: false, status: 400, error: 'scheduled_close_at must be after scheduled_open_at' } };

// Status defaults to 'scheduled' unless the open time is already in the past, in which case 'open'.
const status = openMs <= Date.now() ? 'open' : 'scheduled';

return { json: {
  body: {
    avatar_id:                 avs[0].id,
    item_title:                x.item_title,
    item_description:          x.item_description,
    item_category:             x.item_category,
    item_photos:               [],
    reserve_price_cents:       x.reserve_price_cents,
    min_increment_cents:       x.min_increment_cents,
    scheduled_open_at:         x.scheduled_open_at,
    scheduled_close_at:        x.scheduled_close_at,
    anti_snipe_window_seconds: x.anti_snipe_window_seconds,
    anti_snipe_extend_seconds: x.anti_snipe_extend_seconds,
    anti_snipe_max_extensions: x.anti_snipe_max_extensions,
    status:                    status
  }
} };

const x = $('Check Admin').item.json;
if (!x.auction_id) return { json: { ok: false, status: 400, error: 'auction_id required for cancel' } };
return { json: { auction_id: x.auction_id, body: { status: 'cancelled', actual_close_at: new Date().toISOString(), updated_at: new Date().toISOString() } } };

// Update is for editing fields on a scheduled auction before it opens.
// Forbids changes to amounts after bidding has started.
const x = $('Check Admin').item.json;
if (!x.auction_id) return { json: { ok: false, status: 400, error: 'auction_id required for update' } };
const body = { updated_at: new Date().toISOString() };
if (x.item_title)        body.item_title        = x.item_title;
if (x.item_description !== null) body.item_description = x.item_description;
if (x.item_category !== null)    body.item_category    = x.item_category;
if (x.reserve_price_cents != null) body.reserve_price_cents = x.reserve_price_cents;
if (x.min_increment_cents != null) body.min_increment_cents = x.min_increment_cents;
if (x.scheduled_open_at)  body.scheduled_open_at  = x.scheduled_open_at;
if (x.scheduled_close_at) body.scheduled_close_at = x.scheduled_close_at;
if (Object.keys(body).length === 1) {
  return { json: { ok: false, status: 400, error: 'No fields to update' } };
}
return { json: { auction_id: x.auction_id, body: body } };

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
// Try each source in order; only the relevant one fires per request.
const src = ['Insert Auction', 'Patch Cancel', 'Patch Update'].find(function (n) {
  try { return $(n).all().length > 0; } catch (e) { return false; }
});
if (!src) return { json: { ok: false, status: 500, error: 'No action completed' } };
const rows = allOf(src);
if (rows.length === 0) return { json: { ok: false, status: 404, error: 'No row returned by ' + src + ' (probably wrong status or not found)' } };
return { json: { ok: true, action: $('Check Admin').item.json.action, auction: rows[0] } };
